import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Login() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://127.0.0.1:8000/api/login', { username, password });
      localStorage.setItem('token', response.data.access_token);
      alert("Login Successful!");
      window.location.href = "/"; // Force refresh to update App state
    } catch (err) {
      alert("Invalid Username or Password");
    }
  };

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <h2>System mein Login Karein</h2>
      <form onSubmit={handleLogin}>
        <input type="text" placeholder="Username" onChange={(e) => setUsername(e.target.value)} required style={{padding: '8px', margin: '5px'}} /><br/>
        <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} required style={{padding: '8px', margin: '5px'}} /><br/>
        <button type="submit" style={{ backgroundColor: '#2ecc71', color: 'white', padding: '10px 20px', border: 'none', cursor: 'pointer' }}>Login</button>
      </form>
    </div>
  );
}
export default Login;
